onSubmit:
{{
  appsmith.store.isEditingCustomer 
    ? UpdateCustomer_API.run(
        () => {
          showAlert("Customer Updated Successfully! ✨", "success");
          storeValue('isEditingCustomer', false);
          closeModal('ModalCreateCustomer');
          getCustomers.run(); 
        },
        () => {
          showAlert("Failed to update customer.", "error");
        }
      )
    : showAlert("Click Edit before saving changes.", "info")
}}

state.options:
{{ 
  Location_Data.getStates().map(state => ({
    label: String(state.label || state),
    value: String(state.value || state)
  })) 
}}

dse_id.options:
{{ 
  getDSEs.data.map(item => ({
    label: item.full_name,
    value: item.id // or item.channel_name, as long as it is unique
  })) 
}}

